  // ?湔 getColorFromProbability ?賣
  function getColorFromProbability(prob) {
    if (prob < 0) prob = 0;
    if (prob > 1) prob = 1;
    
    const colors = [
      { stop: 0.0, r: 0, g: 45, b: 255 },     // 瘛梯???
      { stop: 0.2, r: 0, g: 95, b: 255 },     // ?
      { stop: 0.33, r: 0, g: 255, b: 255 },    // 瘛箄???
      { stop: 0.4, r: 0, g: 255, b: 130 },    // ????
      { stop: 0.45, r: 84, g: 255, b: 0 },     // 蝬
      { stop: 0.55, r: 255, g: 255, b: 0 },    // 暺
      { stop: 0.7, r: 255, g: 125, b: 0 },    // 璈
      { stop: 0.8, r: 255, g: 29, b: 0 },     // 璈???
      { stop: 0.9, r: 234, g: 0, b: 0 },      // 蝝
      { stop: 1.0, r: 198, g: 0, b: 0 }       // 瘛梁???
    ];

    // ?風憿????曉?嗅?璈???函???
    for (let i = 0; i < colors.length - 1; i++) {
      const start = colors[i];
      const end = colors[i + 1];

      if (prob >= start.stop && prob <= end.stop) {
        const ratio = (prob - start.stop) / (end.stop - start.stop); // 閮??潭?靘?

        // 蝺扳??潸?蝞?RGB ??
        const r = Math.floor(start.r + ratio * (end.r - start.r));
        const g = Math.floor(start.g + ratio * (end.g - start.g));
        const b = Math.floor(start.b + ratio * (end.b - start.b));

        return `rgb(${r}, ${g}, ${b})`;
      }
    }

    return `rgb(0, 45, 255)`; // ?身餈?瘛梯???
  }
  // 閫??瑼??批捆
  function parseFileContent(content) {
    const generations = {}; // 摮瘥?隞??鞈?

    // 撠摰寞?銵???
    const lines = content.trim().split('\n');

    lines.forEach((line) => {
      // ? generation 鞈???摮?閮?
      const firstColonIndex = line.indexOf(':');
      const generationInfo = line.substring(0, firstColonIndex); // 蝚??????Ｕ?鞈?
      const particlesInfo = line.substring(firstColonIndex + 1); // 蝚??????Ｕ?鞈?
      
      const generationMatch = generationInfo.match(/\*(\d+)\s+(\d+)/);

      if (generationMatch) {
        const generation = parseInt(generationMatch[1], 10); // 隞?
        const bestFitness = parseFloat(generationMatch[2]);  // ?雿?fitness


        const particles = particlesInfo.trim().replace(/\/$/, '').split('/').map((particleStr) => {
          const [fitness, particleInfo, ...bitData] = particleStr.trim().split(' ');

          const bits = bitData.map((bitStr) => {
            const [selected, probability, bitInfo] = bitStr.split(',');
            return {
              selected: parseInt(selected, 10),       // ?臬?豢?閰?bit
              probability: parseFloat(probability),   // 鋡恍銝剔?璈?
              bitInfo: bitInfo,                       // bit 鞈?
            };
          });

          return {
            fitness: parseFloat(fitness), // 蝎???fitness
            particleInfo: particleInfo,   // 蝎???bag ?迂
            bits: bits,                   // bits ?敦蝭鞈?
          };
        });

        // 靽???generations
        generations[generation] = {
          bestFitness: bestFitness, // ?雿?fitness
          particles: particles,     // 蝎?鞈?
        };
      }
    });

    //console.log(generations); // 蝣箄?閫??蝯?

    // ???嗡誨?雿唾圾&甇瑕?雿唾圾
    currentBestPartilce = {};
    currentWorstParticle = {};
    historyBestParticle = {};
    historyWorstParticle = {};

    const allGenerations = Object.keys(generations).map(Number).sort((a, b) => a - b);

    // **?曉??誨?貊??雿?fitness 頞典 (?憭?or ?撠?**
    const firstGen = allGenerations[0];
    isMinimization = true; // ?身?箄?撠?憟?
    if (firstGen) {
      const fitnessValues = generations[firstGen].particles.map(p => p.fitness);
      const bestFitness = generations[firstGen].bestFitness;
      isMinimization = bestFitness === Math.min(...fitnessValues); // 憒? `bestFitness` ?航府隞??撠潘??”蝷箸?撠???
    }

    let bestSolution = null;
    let bestFitnessOverall = -Infinity;
    let worstSolution = null;
    let worstFitnessOverall = Infinity;
    if (isMinimization) {
      bestFitnessOverall = Infinity;
      worstFitnessOverall = -Infinity;
    }

    // **?曉甇瑕?雿唾圾 (??嗅?隞?)**
    for (const gen of allGenerations) {
      const genData = generations[gen];
      
      // **敺?誨?貊????摮葉嚗??`fitness == bestFitness` ??摮?*
      let bestParticle = genData.particles[0]; // ?身?洵銝??
      let worstParticle = genData.particles[0];
      if (isMinimization) {
        bestParticle = genData.particles.reduce((best, p) => (p.fitness < best.fitness ? p : best), genData.particles[0]);
        worstParticle = genData.particles.reduce((worst, p) => (p.fitness > worst.fitness ? p : worst), genData.particles[0]);
      } else {
        bestParticle = genData.particles.reduce((best, p) => (p.fitness > best.fitness ? p : best), genData.particles[0]);
        worstParticle = genData.particles.reduce((worst, p) => (p.fitness < worst.fitness ? p : worst), genData.particles[0]);
      }
      const bestFitness = bestParticle.fitness;
      const worstFitness = worstParticle.fitness;
      
      // ?ㄐ?典?撠???賣???憿?銋?閬???
      if (!isMinimization && bestFitness > bestFitnessOverall) {
        bestFitnessOverall = bestFitness;
        bestSolution = bestParticle;
      } else if (isMinimization && bestFitness < bestFitnessOverall) {
        bestFitnessOverall = bestFitness;
        bestSolution = bestParticle;
      }

      if (!isMinimization && worstFitness < worstFitnessOverall) {
        worstFitnessOverall = worstFitness;
        worstSolution = worstParticle;
      } else if (isMinimization && worstFitness > worstFitnessOverall) {
        worstFitnessOverall = worstFitness;
        worstSolution = worstParticle;
      }

      currentBestPartilce[gen] = {
        bestFitness: bestFitness, // ?雿?fitness
        particles: bestParticle,  // 蝎?鞈?
      };

      currentWorstParticle[gen] = {
        bestFitness: worstFitness,
        particles: worstParticle,
      };

      historyBestParticle[gen] = {
        bestFitness: bestFitnessOverall, // ?雿?fitness
        particles: bestSolution,  // 蝎?鞈?
      };

      historyWorstParticle[gen] = {
        bestFitness: worstFitnessOverall,
        particles: worstSolution,
      };
    }

    return generations;
  }

  function loadEpinFile(file) {
    if (!file) return;

    const fileName = file.name ? file.name.toLowerCase() : '';
    if (!fileName.endsWith('.epin')) {
      window.alert('Please use a .epin file.');
      return;
    }

    if (fileNameDisplay) {
      fileNameDisplay.textContent = file.name;
      fileNameDisplay.title = file.name;
    }

    const reader = new FileReader();
    reader.onload = function (e) {
      const content = e.target.result;
      generations = parseFileContent(content);
      currentGeneration = 0;
      totalGenerations = Object.keys(generations).length;
      updateProgressBar(0);
      updateGrid();
    };
    reader.readAsText(file);
  }

  function setDragDropActive(isActive) {
    DynVisBox.classList.toggle('dragover', isActive);
  }

  function getSortedParticles(particles) {
    const particlesWithIndex = particles.map((particle, originalIndex) => ({
      particle,
      originalIndex,
    }));

    if (particleSortMode === 'fitness-asc') {
      return particlesWithIndex.sort((a, b) => a.particle.fitness - b.particle.fitness);
    }

    if (particleSortMode === 'fitness-desc') {
      return particlesWithIndex.sort((a, b) => b.particle.fitness - a.particle.fitness);
    }

    return particlesWithIndex;
  }
  // ?湔?脣漲璇??澆?憿舐內??generation ??
  function updateProgressBar(generation) {
    if (animationFrameId) return; // 憒????急?蝔?撠勗?銝?銴?瘙?
    animationFrameId = requestAnimationFrame(() => {
      const percentage = (generation / totalGenerations) * 100;
      progressBar.style.width = `${percentage}%`; // 閮剖??脣漲璇祝摨?
      progressText.textContent = `${generation} / ${totalGenerations} (generation)`;
      animationFrameId = null; // ??瑁?摰敺?蝛?
    });
  }
  // ??皛?暺?雿蔭嚗?蝞??? generation
  function setGenerationFromEvent(event) {
    const rect = progressContainer.getBoundingClientRect();
    const offsetX = event.clientX - rect.left; // 皛?暺??詨??潮脣漲璇? X 雿蔭
    const percentage = offsetX / rect.width; // 閮?暺?雿蔭瘥?
    currentGeneration = Math.round(percentage * totalGenerations); // 頧???generation ?詨?
    currentGeneration = Math.max(1, Math.min(totalGenerations, currentGeneration)) - 1; // ?蝭?
    updateProgressBar(currentGeneration + 1);
    updateGrid(); // ?湔 DynVisBox
  }
  // ???剜?
  function startPlayback() {
    playInterval = setInterval(() => {
      // 憒?撌脫?曉?敺?隞???芸??怠?
      if (currentGeneration >= Object.keys(generations).length - 1) {
        clearInterval(playInterval); // 皜閮???
        isPlaying = false;
        playPauseBtn.textContent = 'Play'; // ?湔????
        currentGeneration = 0;
        Genlast = true;
      } else {
        if (Genlast) {
          updateGrid(); // ?湔 DynVisBox
          updateProgressBar(currentGeneration + 1); // ?郊?湔?脣漲璇?
          Genlast = false;
        } else {
          currentGeneration++; // ?脣銝?隞?
          updateGrid(); // ?湔 DynVisBox
          updateProgressBar(currentGeneration + 1); // ?郊?湔?脣漲璇?
        }

      }
    }, 1000 / playbackSpeed); // ?寞??漲??隤踵??
  }
